#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0; getchar(); // consume newline after T
    char buf[105];
    for(int tc=0; tc<T; ++tc){
        if(!fgets(buf, sizeof(buf), stdin)) buf[0]='\0';
        size_t len = strlen(buf);
        if(len && buf[len-1]=='\n') buf[--len]='\0'; // remove trailing newline
        // uppercase version
        for(size_t i=0;i<len;++i) buf[i]=toupper((unsigned char)buf[i]);
        printf("%s\n", buf);
        // vowel count
        int vowels=0;
        for(size_t i=0;i<len;++i) if(strchr("AEIOU", buf[i])) ++vowels;
        printf("%d\n", vowels);
        // palindrome check (case‑insensitive)
        int isPal=1;
        for(size_t i=0;i<len/2;++i){
            char a=tolower((unsigned char)buf[i]);
            char b=tolower((unsigned char)buf[len-1-i]);
            if(a!=b){ isPal=0; break; }
        }
        printf(isPal?"Palindrome\n":"Not a Palindrome\n");
    }
    return 0;
}

