        cout<<upper<<"\n";
        int vowels=0; for(char c:upper) if(string("AEIOU").find(c)!=string::npos) ++vowels;
        cout<<vowels<<"\n";
        string low=line; for(char &c:low) c=tolower((unsigned char)c);
        bool isPal=true; for(size_t i=0;i<low.size()/2;++i){ if(low[i]!=low[low.size()-1-i]){ isPal=false; break; } }
        cout<<(isPal?"Palindrome":"Not a Palindrome")<<"\n";
    }
    return 0;
}

