const input = fs.readFileSync(0, 'utf-8').split('\n');
let T = parseInt((input[0]||'').trim(), 10) || 0;
let idx = 1;
let out = [];
for(let tc=0; tc<T; ++tc){
  let s = input[idx] !== undefined ? input[idx] : '';
  idx++;
  let upper = s.toUpperCase();
  out.push(upper);
  let vowels = 0;
  for(let ch of upper) if('AEIOU'.includes(ch)) vowels++;
  out.push(String(vowels));
  let low = s.toLowerCase();
  let rev = low.split('').reverse().join('');
  out.push(low===rev ? 'Palindrome' : 'Not a Palindrome');
}
